#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;

class KernelCa6k00246Custom {
public:
    __aicore__ inline KernelCa6k00246Custom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t N, uint32_t inC, uint32_t inH, uint32_t inW,
                                uint32_t upscaleFactor,
                                uint32_t totalOutLen, uint32_t tileLen) {
        N_ = N;
        inC_ = inC;
        inH_ = inH;
        inW_ = inW;
        upscaleFactor_ = upscaleFactor;
        totalOutLen_ = totalOutLen;
        tileLen_ = tileLen;

        outC_ = inC_ / (upscaleFactor_ * upscaleFactor_);
        outH_ = inH_ * upscaleFactor_;
        outW_ = inW_ * upscaleFactor_;

        xGm_.SetGlobalBuffer((__gm__ float*)x, N_ * inC_ * inH_ * inW_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalOutLen_);
    }

    __aicore__ inline void Process() {
        uint32_t blockNum = AscendC::GetBlockNum();
        uint32_t blockIdx = AscendC::GetBlockIdx();
        uint32_t stride = blockNum * tileLen_;
        uint32_t start = blockIdx * tileLen_;
        if (start >= totalOutLen_) return;

        for (uint32_t i = start; i < totalOutLen_; i += stride) {
            uint32_t curLen = (i + tileLen_ <= totalOutLen_) ? tileLen_ : (totalOutLen_ - i);
            ProcessTile(i, curLen);
        }
    }

private:
    __aicore__ inline void ProcessTile(uint32_t outStart, uint32_t len) {
        for (uint32_t j = 0; j < len; j++) {
            uint32_t outIdx = outStart + j;
            uint32_t n = outIdx / (outC_ * outH_ * outW_);
            uint32_t remainder = outIdx % (outC_ * outH_ * outW_);
            uint32_t c = remainder / (outH_ * outW_);
            remainder = remainder % (outH_ * outW_);
            uint32_t h = remainder / outW_;
            uint32_t w = remainder % outW_;

            uint32_t inC_idx = c * upscaleFactor_ * upscaleFactor_ +
                               (h % upscaleFactor_) * upscaleFactor_ +
                               (w % upscaleFactor_);
            uint32_t inH_idx = h / upscaleFactor_;
            uint32_t inW_idx = w / upscaleFactor_;

            uint32_t inIdx = ((n * inC_ + inC_idx) * inH_ + inH_idx) * inW_ + inW_idx;
            yGm_[outIdx] = xGm_[inIdx];
        }
    }

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t N_;
    uint32_t inC_;
    uint32_t inH_;
    uint32_t inW_;
    uint32_t upscaleFactor_;
    uint32_t totalOutLen_;
    uint32_t tileLen_;

    uint32_t outC_;
    uint32_t outH_;
    uint32_t outW_;
};

extern "C" __global__ __aicore__ void ca6k_00246_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling) {
